import{_ as r,o as t,c as n,j as e,a as o,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"哦！寂寞的我","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/哦！寂寞的我.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/哦！寂寞的我.md"}'),p={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/哦！寂寞的我.md"};function d(_,a,l,i,b,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"哦-寂寞的我",tabindex:"-1"},[o("哦！寂寞的我 "),e("a",{class:"header-anchor",href:"#哦-寂寞的我","aria-label":'Permalink to "哦！寂寞的我"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),s('<h1 id="哦-寂寞的我-1" tabindex="-1">哦！寂寞的我 <a class="header-anchor" href="#哦-寂寞的我-1" aria-label="Permalink to &quot;哦！寂寞的我&quot;">​</a></h1><p>哦！寂寞的我（Oh! Lonesome Me）</p><p>C+1200</p><p>“我并不期待能死在病床上，我是个牛仔。我只求一个能回去的地方……一个在远游之后，还等着我回去的地方。”</p><p>拥有将绳子穿过自己的身体，让身体沿着绳子分裂并「滑」到绳子子的另一端重组的能力。还可以对其他人施展这种能力。</p><p>替身名：哦！寂寞的我（Oh! Lonesome Me）<br> 类型：非人型<br> 检定属性：力量<br> 替身数据：<br> 破坏力E<br> 速度D（闪避防御）<br> 射程C<br> 持续力B<br> 精密动作性C<br> 成长性C</p><p>替身能力：能够让身体分裂开来，在绳子上移动，可以通过这种方式通过一些狭窄的地方。当通过绳子擒抱住其他生物后，可通过一个标准动作对其攻击，强韧豁免伤害，但是本次攻击不造成伤害，而是造成一种特殊的肢体残障点数，使用标准强韧豁免进行对抗。这种特殊的肢体残障表现为目标肢体被分裂成绳子而无法使用，并且在进入毁灭性后果后不是永久失去肢体，而是会因身体被彻底分裂成无数块而进入无助状态。分裂其他生物的替身能力只能作用到力量/2米距离内，当超过距离的时候需要接近目标生物到力量/2米内才能发动替身能力。被替身攻击所造成的异常点数将至多存在两个小时，或被替身使者主动收回能力。</p><p>控绳大师（1—3）<br> 1级：通过替身能力将手分裂到绳子末端的时候并且可以正常使用。<br> 2级：想要熟练应用替身能力的前提是熟练地控绳，现在你能用用绳子造成严重伤害，并且也能用在绳子末端的手进行开枪之类的攻击动作。当以绳子进行过一次擒抱攻击后，还可以再使被攻击者进行反射豁免，以拖拽其二者差值的距离。<br> 3级：现在对替身能力熟练应用让你可以用一个自由动作将身体沿着绳子快速滑动20米。现在，绳子将最多可以延伸至力量/3米。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
